#include<bits/stdc++.h>using namespace std;int k,n,ans=0;string s,t;int Mex(string s0,string s1){	int b[20]={0,0,0};	for(int i=0;i<s0.size();i++){		b[s0[i]-'0']++;		b[s1[i]-'0']++;	}	for(int i=0;i<3;i++){		if(b[i]==0) return i;	}}int main(){	cin>>k;	while(k--){		cin>>n>>s>>t;		string s1="",t1="";		s1=s1+s[0];		t1=t1+t[0];		int mex=Mex(s1,t1);		for(int i=1;i<s.size();i++){			if(mex==0){				s1=s1+s[i];				t1=t1+t[i];				mex=Mex(s1,t1);			}else if(mex==2){				ans+=mex;				s1="";t1="";				s1=s1+s[i];				t1=t1+t[i];				mex=Mex(s1,t1);			}else if(mex==1){				if(s[i]=='0'&&t[i]=='0'){					ans+=mex;					s1="";t1="";					s1=s1+s[i];					t1=t1+t[i];					mex=Mex(s1,t1);				}else if(s[i]=='1'&&t[i]=='1'){					s1=s1+s[i];					t1=t1+t[i];					mex=Mex(s1,t1);				}else{					ans+=mex;					s1="";t1="";					s1=s1+s[i];					t1=t1+t[i];					mex=Mex(s1,t1);				}			}		}		ans+=mex;		cout<<ans<<endl;		ans=0;	}		return 0;}